import{_ as t,o as e,c as i,a2 as n}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"gm/operasional-layanan.md","filePath":"gm/operasional-layanan.md"}'),r={name:"gm/operasional-layanan.md"};function s(l,a,o,d,h,k){return e(),i("div",null,[...a[0]||(a[0]=[n('<h2 id="bab-8-dashboard-tab-2-—-operasional-layanan" tabindex="-1">BAB 8: DASHBOARD TAB 2 — OPERASIONAL &amp; LAYANAN <a class="header-anchor" href="#bab-8-dashboard-tab-2-—-operasional-layanan" aria-label="Permalink to &quot;BAB 8: DASHBOARD TAB 2 — OPERASIONAL &amp; LAYANAN&quot;">​</a></h2><p>Tab ini memindahkan fokus Anda dari angka keuangan ke <strong>kondisi fisik kafe dan kualitas pelayanan</strong>.</p><h3 id="_8-1-ai-insight-kebersihan-higienisitas" tabindex="-1">8.1 AI Insight: Kebersihan (Higienisitas) <a class="header-anchor" href="#_8-1-ai-insight-kebersihan-higienisitas" aria-label="Permalink to &quot;8.1 AI Insight: Kebersihan (Higienisitas)&quot;">​</a></h3><p>Kotak ini menampilkan lingkaran persentase skor kebersihan rata-rata, disertai kesimpulan otomatis:</p><table tabindex="0"><thead><tr><th>Kondisi</th><th>Pesan AI</th></tr></thead><tbody><tr><td>Omset tembus target, tapi kebersihan &lt; 95%</td><td><strong>&quot;Sales Naik, SOP Turun&quot;</strong> — Tim kelelahan, kebersihan terbengkalai saat ramai</td></tr><tr><td>Omset gagal, dan kebersihan &lt; 95%</td><td><strong>&quot;Peringatan Ganda&quot;</strong> — Butuh intervensi segera</td></tr><tr><td>Semua beres (SOP &gt; 95%)</td><td><strong>&quot;The Good Standard&quot;</strong> — Standar terjaga</td></tr></tbody></table><h3 id="_8-2-area-kritis-kebersihan" tabindex="-1">8.2 Area Kritis (Kebersihan) <a class="header-anchor" href="#_8-2-area-kritis-kebersihan" aria-label="Permalink to &quot;8.2 Area Kritis (Kebersihan)&quot;">​</a></h3><p>Jika ada area kafe yang skornya di bawah 95%, sistem menampilkannya di sini dalam kotak merah menyala:</p><ul><li>Contoh: &quot;1. Toilet (Skor: 90%) — Bersih&quot;</li><li>Anda langsung tahu titik lemah outlet tanpa perlu membaca laporan panjang</li></ul><h3 id="_8-3-galeri-pengeluaran-bahan-atk" tabindex="-1">8.3 Galeri Pengeluaran (Bahan &amp; ATK) <a class="header-anchor" href="#_8-3-galeri-pengeluaran-bahan-atk" aria-label="Permalink to &quot;8.3 Galeri Pengeluaran (Bahan &amp; ATK)&quot;">​</a></h3><p>Tampilan geser horizontal (<em>slider</em>) yang menampilkan foto nota belanja SPV beserta nama item dan harganya.</p><ul><li>Jika kosong: &quot;Aman. Tidak ada pengeluaran di periode ini&quot;</li><li>Klik foto untuk memperbesar (verifikasi nota, cegah fraud nota fiktif)</li></ul><h3 id="_8-4-maintenance-eskalasi-fasilitas" tabindex="-1">8.4 Maintenance &amp; Eskalasi Fasilitas <a class="header-anchor" href="#_8-4-maintenance-eskalasi-fasilitas" aria-label="Permalink to &quot;8.4 Maintenance &amp; Eskalasi Fasilitas&quot;">​</a></h3><p>Galeri foto berwarna kemerahan berisi aset yang butuh perbaikan:</p><ul><li>Menampilkan foto kerusakan yang diunggah SPV</li><li>Jika item ditandai &quot;Eskalasi GM&quot; oleh SPV, muncul di sini</li><li>Jumlah tiket eskalasi tertulis di pojok kanan</li></ul><h3 id="_8-5-statistik-komplain-qc" tabindex="-1">8.5 Statistik Komplain &amp; QC <a class="header-anchor" href="#_8-5-statistik-komplain-qc" aria-label="Permalink to &quot;8.5 Statistik Komplain &amp; QC&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Total Komplain</th><th>Warna</th></tr></thead><tbody><tr><td>0</td><td>Hijau (Aman)</td></tr><tr><td>1</td><td>Kuning (Waspada)</td></tr><tr><td>2</td><td>Oranye (Batas Maksimal)</td></tr><tr><td>&gt; 2</td><td><strong>Merah (KPI Dilanggar)</strong></td></tr></tbody></table><hr>',17)])])}const p=t(r,[["render",s]]);export{u as __pageData,p as default};
